proof fn phi_3_bit_ranges_non_overlapping()
    ensures
        bitmask_inc!(39usize, 47usize) & bitmask_inc!(30usize, 38usize) == 0,
        bitmask_inc!(30usize, 38usize) & bitmask_inc!(21usize, 29usize) == 0,
        bitmask_inc!(21usize, 29usize) & bitmask_inc!(12usize, 20usize) == 0,
{
    assert(bitmask_inc!(39usize, 47usize) & bitmask_inc!(30usize, 38usize) == 0) by (bit_vector);
    assert(bitmask_inc!(30usize, 38usize) & bitmask_inc!(21usize, 29usize) == 0) by (bit_vector);
    assert(bitmask_inc!(21usize, 29usize) & bitmask_inc!(12usize, 20usize) == 0) by (bit_vector);
}

proof fn phi_4_all_index_bits_reconstruct_addr(va: usize)
    ensures
        (l0_bits!(va) << 39usize) | (l1_bits!(va) << 30usize) | (l2_bits!(va) << 21usize) | (l3_bits!(va) << 12usize)
            == va & bitmask_inc!(12usize, 47usize),
{
    assert((l0_bits!(va) << 39usize) | (l1_bits!(va) << 30usize) | (l2_bits!(va) << 21usize) | (l3_bits!(va) << 12usize)
        == va & bitmask_inc!(12usize, 47usize)) by (bit_vector);
}

proof fn phi_5_bits_ignore_high_48_plus(va: usize)
